  if($schema<21) $data['products']=array_values(array_filter($data['products'],fn($product)=>(int)($product['id']??0)!==31661));
  foreach($data['products'] as &$product){
    $price=(int)($product['price']??0);
    if(!array_key_exists('points_reward',$product)) $product['points_reward']=max(10,min(500,(int)floor($price/1000)*5));
  }
  $defaults=[
    ['code'=>'JAGOBARU10','description'=>'Diskon 10% untuk pelanggan baru','type'=>'percent','value'=>10,'minSubtotal'=>25000,'maxUses'=>0,'used'=>0,'enabled'=>true,'expiresAt'=>'','requiredCategory'=>'','minQuantity'=>1,'requireSameProduct'=>false],
    ['code'=>'HEMAT5000','description'=>'Potongan Rp5.000 minimal belanja Rp50.000','type'=>'amount','value'=>5000,'minSubtotal'=>50000,'maxUses'=>0,'used'=>0,'enabled'=>true,'expiresAt'=>'','requiredCategory'=>'','minQuantity'=>1,'requireSameProduct'=>false],
    ['code'=>'JAGOPREM7','description'=>'Diskon 7% minimal belanja Rp75.000','type'=>'percent','value'=>7,'minSubtotal'=>75000,'maxUses'=>0,'used'=>0,'enabled'=>true,'expiresAt'=>'','requiredCategory'=>'','minQuantity'=>1,'requireSameProduct'=>false]
  ];
  $legacyCodes=['SPESIALAI07','AIHEMAT20'];
  $data['vouchers']=array_values(array_filter($data['vouchers'],fn($voucher)=>!in_array(normalize_voucher_code((string)($voucher['code']??'')),$legacyCodes,true)));
  foreach($defaults as $voucher){ $found=false; foreach($data['vouchers'] as $existing) if(normalize_voucher_code((string)($existing['code']??''))===$voucher['code']){$found=true;break;} if(!$found){$voucher['createdAt']=now_iso();$data['vouchers'][]=$voucher;} }
  if(empty($data['reviews'])) $data['reviews']=[
    ['id'=>'rev-jago-01','orderId'=>'seed-01','productId'=>2,'userId'=>'seed-user-01','customerName'=>'Raka P.','rating'=>5,'comment'=>'Prosesnya cepat, akun private langsung dikirim ke WhatsApp dan sampai sekarang aman.','verified'=>true,'createdAt'=>'2026-07-18T09:15:00Z'],
    ['id'=>'rev-jago-02','orderId'=>'seed-02','productId'=>1,'userId'=>'seed-user-02','customerName'=>'Nabila A.','rating'=>5,'comment'=>'CS responsif dan QRIS-nya langsung sesuai total, jadi tidak perlu input nominal lagi.','verified'=>true,'createdAt'=>'2026-07-16T12:40:00Z'],
    ['id'=>'rev-jago-03','orderId'=>'seed-03','productId'=>29,'userId'=>'seed-user-03','customerName'=>'Fikri R.','rating'=>4,'comment'=>'Pengiriman Spotify cepat. Petunjuk login juga jelas dan mudah diikuti.','verified'=>true,'createdAt'=>'2026-07-14T04:22:00Z'],
    ['id'=>'rev-jago-04','orderId'=>'seed-04','productId'=>5,'userId'=>'seed-user-04','customerName'=>'Salsa M.','rating'=>5,'comment'=>'Sudah repeat order, admin ramah dan garansinya benar-benar dibantu saat ada kendala.','verified'=>true,'createdAt'=>'2026-07-11T16:08:00Z']
  ];
  foreach($data['users'] as &$user){ if(empty($user['referralCode']))$user['referralCode']=referral_code($user); $user['points']=(int)($user['points']??0); $user['pointsPending']=(int)($user['pointsPending']??0); $user['referralCount']=(int)($user['referralCount']??0); $user['whatsapp']=normalize_whatsapp((string)($user['whatsapp']??''),false); }
  refresh_sales_counts($data);
}
function clean_email(string $v): string { return strtolower(trim($v)); }
function normalize_whatsapp(string $value,bool $strict=true): string {
  $raw=preg_replace('/[\s()\-\.]/','',trim($value));
  if($raw==='') return '';
  if(str_starts_with($raw,'+')) $raw=substr($raw,1);
  if(str_starts_with($raw,'08')) $raw='62'.substr($raw,1);
  if(!preg_match('/^628[0-9]{7,12}$/',$raw)) return $strict?'':'';
  return $raw;
}
function refresh_sales_counts(array &$store): void {
  $counts=[];$titleCounts=[];
  foreach($store['orders']??[] as $order){
    if(!in_array((string)($order['status']??''),['completed','success'],true)) continue;
    foreach($order['items']??[] as $line){
      $quantity=max(1,(int)($line['quantity']??1));$id=(int)($line['id']??0);
      if($id>0)$counts[$id]=($counts[$id]??0)+$quantity;
      $titleKey=strtolower((string)preg_replace('/[^a-z0-9]+/i','',(string)($line['title']??'')));
      if($titleKey!=='')$titleCounts[$titleKey]=($titleCounts[$titleKey]??0)+$quantity;
    }
  }
  foreach($store['products'] as &$product){
    $titleKey=strtolower((string)preg_replace('/[^a-z0-9]+/i','',(string)($product['title']??'')));
    $completed=max((int)($counts[(int)($product['id']??0)]??0),(int)($titleCounts[$titleKey]??0));
    $product['sold']=max(0,(int)($product['sold']??0),$completed);
  }
  unset($product);
}
function referral_code(array $u): string { return (string)($u['referralCode']??('JAGO'.strtoupper(substr(preg_replace('/[^a-zA-Z0-9]/','',(string)($u['id']??'')),-6)))); }
function public_user(array $u): array { return ['id'=>$u['id'],'name'=>$u['name'],'email'=>$u['email'],'whatsapp'=>$u['whatsapp']??'','createdAt'=>$u['createdAt']??'','points'=>(int)($u['points']??0),'pointsPending'=>(int)($u['pointsPending']??0),'referralCode'=>referral_code($u),'referralCount'=>(int)($u['referralCount']??0)]; }
