function point_entry_exists(array $store,string $reference): bool { foreach($store['pointLedger']??[] as $entry) if(($entry['reference']??'')===$reference) return true; return false; }
function apply_point_entry(array &$store,string $userId,int $amount,string $type,string $description,string $reference,string $status='active'): bool {
  if($reference!=='' && point_entry_exists($store,$reference)) return false;
  $entry=['id'=>'point-'.bin2hex(random_bytes(8)),'userId'=>$userId,'amount'=>$amount,'type'=>$type,'description'=>$description,'reference'=>$reference,'status'=>$status,'createdAt'=>now_iso()];
  array_unshift($store['pointLedger'],$entry);
  foreach($store['users'] as &$user) if(($user['id']??'')===$userId){ if($status==='pending') $user['pointsPending']=max(0,(int)($user['pointsPending']??0)+$amount); else $user['points']=max(0,(int)($user['points']??0)+$amount); break; }
  return true;
}
function chat_message_key(array $m): string { return (string)($m['id']??(($m['sender']??'').':'.($m['createdAt']??'').':'.($m['text']??''))); }
function latest_timestamp(string ...$values): int { $latest=0; foreach($values as $value){ $time=strtotime($value); if($time!==false && $time>$latest) $latest=$time; } return $latest; }
function chat_unread_count(array $chat): int { $lastRead=strtotime((string)($chat['adminLastReadAt']??''))?:0; $count=0; foreach(($chat['messages']??[]) as $message) if(($message['sender']??'')==='customer' && (strtotime((string)($message['createdAt']??''))?:0)>$lastRead) $count++; return $count; }
function summarize_chat(array $chat): array { $messages=$chat['messages']??[]; $last=$messages? $messages[array_key_last($messages)] : null; return ['id'=>$chat['id'],'userId'=>$chat['userId']??'','orderId'=>$chat['orderId']??'','customer'=>$chat['customer']??[],'status'=>$chat['status']??'open','humanTakeover'=>!empty($chat['humanTakeover']),'escalationReason'=>$chat['escalationReason']??'','internalNote'=>$chat['internalNote']??'','updatedAt'=>$chat['updatedAt']??($last['createdAt']??''),'adminLastReadAt'=>$chat['adminLastReadAt']??'','lastMessageAt'=>$last['createdAt']??($chat['updatedAt']??''),'lastMessageText'=>$last['text']??'','lastMessageSender'=>$last['sender']??'','unreadCount'=>chat_unread_count($chat),'messageCount'=>count($messages)]; }
function merge_chat_messages(array &$target,array $source): void { $seen=[]; foreach(($target['messages']??[]) as $message) $seen[chat_message_key($message)]=true; foreach(($source['messages']??[]) as $message){ $key=chat_message_key($message); if(!isset($seen[$key])){ $target['messages'][]=$message; $seen[$key]=true; } } usort($target['messages'], fn($a,$b)=>strcmp((string)($a['createdAt']??''),(string)($b['createdAt']??''))); }
function claim_user_chat(array &$store,array $user,string $preferredChatId='',array $customer=[]): array {
  $targetId=(string)$user['id'];$email=clean_email((string)($user['email']??''));
  $preferredChatId=preg_match('/^chat-[a-zA-Z0-9-]{3,80}$/',$preferredChatId)?$preferredChatId:'';
  $matching=[];
  foreach($store['chats'] as $index=>$chat){
    $sameUser=($chat['id']??'')===$targetId||($chat['userId']??'')===$targetId;
    $sameGuest=$preferredChatId!==''&&($chat['id']??'')===$preferredChatId&&empty($chat['userId']);
    $sameEmail=$email!==''&&clean_email((string)($chat['customer']['email']??''))===$email;
    if($sameUser||$sameGuest||$sameEmail)$matching[$index]=$chat;
  }
  $target=['id'=>$targetId,'userId'=>$targetId,'customer'=>array_merge(chat_customer($user),$customer),'messages'=>[],'status'=>'ai','humanTakeover'=>false,'updatedAt'=>now_iso()];
  foreach($matching as $chat){
    merge_chat_messages($target,$chat);
    $target['customer']=array_merge($chat['customer']??[],$target['customer'],chat_customer($user),$customer);
    if(!empty($chat['orderId'])&&empty($target['orderId']))$target['orderId']=$chat['orderId'];
    if(!empty($chat['humanTakeover'])){$target['humanTakeover']=true;$target['status']=$chat['status']??'waiting_human';}
    $ts=latest_timestamp((string)($target['adminLastReadAt']??''),(string)($chat['adminLastReadAt']??''));
    if($ts)$target['adminLastReadAt']=gmdate('c',$ts);
  }
  $sourceIds=[];foreach($matching as $chat)if(!empty($chat['id']))$sourceIds[(string)$chat['id']]=true;
  $store['chats']=array_values(array_merge([$target],array_values(array_filter($store['chats'],fn($chat)=>!isset($sourceIds[(string)($chat['id']??'')])&&($chat['id']??'')!==$targetId))));
  foreach($store['orders'] as &$order)if(($order['userId']??'')===$targetId||isset($sourceIds[(string)($order['chatId']??'')]))$order['chatId']=$targetId;
  return $target;
}
function normalize_voucher_code(string $v): string { return strtoupper(preg_replace('/[^A-Z0-9_-]/','',trim($v))); }
function product_category(array $item): string { $title=(string)($item['title']??''); if(preg_match('/SALDO API|PAKET TOKEN/i',$title)) return 'Developer API'; return preg_match('/AI |GPT EDU|CHATGPT|CLAUDE|GROK|GEMINI|PERPLEXITY|KIRO|LEONARDO|KLING/i',$title)?'AI & produktivitas':(preg_match('/IQIYI|HBO|SPOTIFY|YOUTUBE|APPLE MUSIC|PRIME VIDEO|WETV|VIU|VIDIO|BSTATION|LOKLOK|DRAMABOX|REELSHORT/i',$title)?'Hiburan premium':'Aplikasi premium'); }
function product_is_sharing(array $item): bool { $explicit=implode(' ',array_filter([(string)($item['title']??''),(string)($item['access']??''),(string)($item['thumbnail']??'')])); $context=implode(' ',array_filter([(string)($item['title']??''),(string)($item['access']??''),(string)($item['description']??'')])); return preg_match('/sharing/i',$explicit)===1 && preg_match('/(bukan|non[- ]?)\s*sharing|private|privat/i',$context)!==1; }
function safe_product_image(string $value): string { $value=trim($value); if($value==='')return 'assets/jagoprem-mark.png'; if(preg_match('#^assets/[a-zA-Z0-9_./-]+\.(?:png|jpe?g|webp|svg)$#i',$value))return $value; if(filter_var($value,FILTER_VALIDATE_URL)&&strtolower((string)parse_url($value,PHP_URL_SCHEME))==='https')return mb_substr($value,0,500); json_response(['error'=>'URL gambar harus HTTPS atau file di folder assets.'],400); }
function clean_product_fields(array $input): array { foreach(['title','category','access','duration','warranty','description'] as $key)if(isset($input[$key]))$input[$key]=strip_tags((string)$input[$key]); if(isset($input['badges'])&&is_array($input['badges']))$input['badges']=array_map(fn($badge)=>strip_tags((string)$badge),$input['badges']); return $input; }
function sanitize_product_input(array $input,array $base=[]): array {
